import{_ as e,o as i,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Screening X-Ray","description":"","frontmatter":{},"headers":[],"relativePath":"guide/screening.md","filePath":"guide/screening.md"}'),r={name:"guide/screening.md"};function l(o,a,s,d,u,k){return i(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="screening-x-ray" tabindex="-1">Screening X-Ray <a class="header-anchor" href="#screening-x-ray" aria-label="Permalink to &quot;Screening X-Ray&quot;">​</a></h1><p>Halaman ini adalah inti dari aplikasi — tempat operator melakukan pemeriksaan X-Ray terhadap kargo.</p><h2 id="persiapan-kamera" tabindex="-1">Persiapan Kamera <a class="header-anchor" href="#persiapan-kamera" aria-label="Permalink to &quot;Persiapan Kamera&quot;">​</a></h2><ol><li>Pastikan kamera/capture card terhubung ke komputer</li><li>Browser akan meminta izin akses kamera — klik <strong>Izinkan</strong></li><li>Dua panel video akan muncul: <ul><li><strong>Kamera Top View</strong> (kiri) — Kamera atas untuk deteksi koli</li><li><strong>Kamera Side View</strong> (kanan) — Kamera samping</li></ul></li><li>Gunakan dropdown di atas masing-masing panel untuk memilih perangkat kamera jika tersedia lebih dari satu</li></ol><h2 id="input-data-screening" tabindex="-1">Input Data Screening <a class="header-anchor" href="#input-data-screening" aria-label="Permalink to &quot;Input Data Screening&quot;">​</a></h2><p><strong>Cara 1 — Manual:</strong></p><ol><li>Ketik <strong>MAWB</strong> dan <strong>HAWB</strong> pada field input di bawah video</li><li>Sistem akan otomatis mencocokkan dengan data cargo (jika ada) dan mengisi HAWB</li></ol><p><strong>Cara 2 — Scanner OCR Otomatis:</strong></p><ul><li>Jika terintegrasi dengan kamera fixed/scanner, data MAWB/HAWB akan terisi otomatis melalui koneksi SSE (Server-Sent Events)</li><li>Status koneksi ditunjukkan oleh ikon <strong>WiFi</strong> (hijau = terhubung, merah = terputus)</li></ul><p><strong>Cara 3 — Auto Screening (Antrian):</strong></p><ul><li>Aktifkan fitur <strong>Auto Screening</strong> di Pengaturan</li><li>Data dari scanner akan masuk antrian dan diproses otomatis dengan delay yang dapat diatur</li></ul><h2 id="ambil-foto-barang" tabindex="-1">Ambil Foto Barang <a class="header-anchor" href="#ambil-foto-barang" aria-label="Permalink to &quot;Ambil Foto Barang&quot;">​</a></h2><ol><li>Klik area <strong>Foto Barang</strong> (atau tombol Upload)</li><li>Pilih file gambar dari komputer</li><li>Preview akan muncul di panel Foto Barang</li></ol><h2 id="deteksi-koli-dengan-ai" tabindex="-1">Deteksi Koli dengan AI <a class="header-anchor" href="#deteksi-koli-dengan-ai" aria-label="Permalink to &quot;Deteksi Koli dengan AI&quot;">​</a></h2><p>Aplikasi mendukung tiga metode deteksi koli:</p><table tabindex="0"><thead><tr><th>Metode</th><th>Cara Kerja</th><th>Kelebihan</th></tr></thead><tbody><tr><td><strong>OpenCV</strong></td><td>Server-side Python (edge detection + contour finding)</td><td>Akurat, tidak membebani browser</td></tr><tr><td><strong>MediaPipe</strong></td><td>Client-side EfficientDet via WASM</td><td>Cepat, offline, tanpa server</td></tr><tr><td><strong>Manual</strong></td><td>Drag &amp; crop interaktif dengan mouse</td><td>Kontrol penuh oleh operator</td></tr></tbody></table><p><strong>Langkah-langkah:</strong></p><ol><li>Pastikan kamera Top View menampilkan kargo</li><li>Tekan tombol <strong>AI Analyze</strong> — sistem akan mendeteksi koli secara otomatis</li><li>Bounding box hijau akan muncul mengelilingi setiap koli yang terdeteksi</li><li>Hasil crop koli akan muncul di panel <strong>Hasil Crop Koli</strong></li><li>Jumlah koli terdeteksi otomatis mengisi field Qty</li></ol><h2 id="kalibrasi-background-bgs" tabindex="-1">Kalibrasi Background (BGS) <a class="header-anchor" href="#kalibrasi-background-bgs" aria-label="Permalink to &quot;Kalibrasi Background (BGS)&quot;">​</a></h2><p>Untuk hasil deteksi yang lebih akurat dengan metode BGS:</p><ol><li>Pastikan tidak ada kargo di frame kamera (konveyor kosong)</li><li>Klik tombol <strong>Calibrate Background</strong> (ikon kamera)</li><li>Sistem akan menyimpan baseline gambar (maksimal 2)</li><li>Baselines disimpan di localStorage browser</li></ol><h2 id="crop-manual" tabindex="-1">Crop Manual <a class="header-anchor" href="#crop-manual" aria-label="Permalink to &quot;Crop Manual&quot;">​</a></h2><p>Untuk mode <strong>Manual</strong>:</p><ol><li>Pilih metode <strong>Manual</strong> di Pengaturan</li><li>Klik dan drag pada video Top View atau Side View</li><li>Lepaskan mouse untuk menyimpan crop</li><li>Crop akan muncul di panel hasil</li></ol><h2 id="membuat-keputusan" tabindex="-1">Membuat Keputusan <a class="header-anchor" href="#membuat-keputusan" aria-label="Permalink to &quot;Membuat Keputusan&quot;">​</a></h2><p>Setelah data lengkap dan analisis selesai:</p><table tabindex="0"><thead><tr><th>Tombol</th><th>Arti</th></tr></thead><tbody><tr><td><strong>✔ Finished XRay</strong></td><td>Kargo dinyatakan <strong>LOLOS</strong> / release</td></tr><tr><td><strong>✖ Pending XRay</strong></td><td>Kargo dinyatakan <strong>DITOLAK</strong> / perlu pemeriksaan lanjutan</td></tr></tbody></table><p>Setelah memutuskan:</p><ol><li>Klik salah satu tombol keputusan</li><li>Data scan akan disimpan ke database</li><li>Gambar akan diberi watermark (MAWB, HAWB, timestamp)</li><li>Notifikasi sukses akan muncul</li></ol><h2 id="panel-hasil-crop" tabindex="-1">Panel Hasil Crop <a class="header-anchor" href="#panel-hasil-crop" aria-label="Permalink to &quot;Panel Hasil Crop&quot;">​</a></h2><p>Panel ini menampilkan semua hasil crop koli dari deteksi AI atau cropping manual. Setiap crop menampilkan:</p><ul><li>Gambar hasil crop</li><li>Nomor urut koli</li><li>Tombol <strong>X</strong> untuk menghapus crop tertentu</li></ul><h2 id="riwayat-scan-terbaru" tabindex="-1">Riwayat Scan Terbaru <a class="header-anchor" href="#riwayat-scan-terbaru" aria-label="Permalink to &quot;Riwayat Scan Terbaru&quot;">​</a></h2><p>Panel kanan bawah menampilkan 10 scan terakhir untuk referensi cepat operator.</p>',34)])])}const p=e(r,[["render",l]]);export{m as __pageData,p as default};
